class Building:
    def __init__(self, floor_count, elevator_count):
        self.floors = floor_count
        self.elevators = [Elevator(i) for i in range(elevator_count)]
        self.requests = []

    def request_elevator(self, floor, direction):
        self.requests.append((floor, direction))

    def step(self):
        for elevator in self.elevators:
            if elevator.passengers:
                elevator.move()
                if elevator.current_floor in [p['destination'] for p in elevator.passengers]:
                    elevator.passengers = [p for p in elevator.passengers if p['destination'] != elevator.current_floor]
            else:
                if self.requests:
                    floor, direction = self.requests.pop(0)
                    elevator.current_floor = floor
                    elevator.set_direction(direction)
                    elevator.add_passenger({'destination': floor + 1 if direction == 'up' else floor - 1})

