    for hour in range(hours):
        if hour < 9 or hour >= 17:  # Morning and evening rush hours
            for _ in range(crowd_size):
                floor = random.randint(0, building.floors - 1)
                direction = 'up' if floor < building.floors - 1 else 'down'
                building.request_elevator(floor, direction)
        elif 9 <= hour < 17:  # Daytime
            if random.random() < 0.1:  # 10% chance of requests
