    def move_to_floor(self, floor):
        print(f"Elevator {self.id} moving from floor {self.current_floor} to floor {floor}.")
        self.current_floor = floor

    def pick_up(self, person):
        self.passengers.append(person)
        print(f"Elevator {self.id} picked up {person} at floor {self.current_floor}.")

    def drop_off(self, person):
        self.passengers.remove(person)
        print(f"Elevator {self.id} dropped off {person} at floor {self.current_floor}.")

class Building:
    def __init__(self, num_floors, num_elevators):
        self.num_floors = num_floors
        self.elevators = [Elevator(i, num_floors) for i in range(num_elevators)]
        self.people = []

    def generate_people(self, time_of_day):
        if time_of_day in ['morning', 'evening']:
            num_people = random.randint(20, 50)
        elif time_of_day == 'day':
            num_people = random.randint(5, 15)
        else:
            num_people = random.randint(0, 5)

        for _ in range(num_people):
            floor = random.randint(0, self.num_floors - 1)
            self.people.append(f"Person at floor {floor}")

    def operate_elevators(self):
        for person in self.people:
            floor = int(person.split()[3])
            elevator = random.choice(self.elevators)
            elevator.move_to_floor(floor)
            elevator.pick_up(person)
            drop_off_floor = random.randint(0, self.num_floors - 1)
            elevator.move_to_floor(drop_off_floor)
            elevator.drop_off(person)

